'use client';
import { useEffect, useState } from 'react';
import { useToast } from '@/hooks/use-toast';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Skeleton } from '@/components/ui/skeleton';
import { EventCategory } from '@/types';
import { useDebounce } from 'use-debounce';
import { motion, AnimatePresence } from 'framer-motion';
import { DollarSign, Download, Gift, Icon, Rocket, Search } from 'lucide-react';
import EventCard from '@/components/ui/EventCard';
import Link from 'next/link';
import UnregisterConfirmationDialog from '@/components/dialog/UnregisterConfirmationDialog';
import { useAuth } from '@/context/AuthContext';
import RegisterConfirmationDialog from '@/components/dialog/RegisterConfirmationDialog';
import Pagination from '@/components/ui/Pagination';
import { fetchEvents } from '@/api/events/events';
import NotFound from '@/components/ui/NotFound';
import { filters } from '@/constants/filters';
import { Loading } from '@/components/ui/Loading';

const UserDashboard = () => {
  const { toast } = useToast();
  const { token, detailsProfile } = useAuth();
  const [events, setEvents] = useState<EventCategory[]>([]);
  const [activeFilter, setActiveFilter] = useState<
    'all' | 'upcoming' | 'past'
  >('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [debouncedQuery] = useDebounce(searchQuery, 300);
  const [selectedEvent, setSelectedEvent] = useState<EventCategory | null>(
    null
  );
  const[isPrice,setIsPrice]=useState(false);
  const[isFree,setIsFree]=useState(false);

  const [isUnregisterModalOpen, setIsUnregisterModalOpen] = useState(false);
  const [isRegisterModalOpen, setIsRegisterModalOpen] = useState(false);
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(0);
  const [totalItems, setTotalItems] = useState(0);
  const [eventsPerPage] = useState(6);
  const [loading, setLoading] = useState(false);
  const [downloadingInvoice, setDownloadingInvoice] = useState<string | null>(
    null
  );

  const currentEvents = (events || []).filter((event) => {
    const matchesSearch = event.title
      .toLowerCase()
      .includes(debouncedQuery.toLowerCase());
    
    // فلتر حسب النوع الأساسي (all, upcoming, past)
    const matchesBasicFilter =
      activeFilter === 'all' ||
      (activeFilter === 'upcoming' && event.status === 'upcoming') ||
      (activeFilter === 'past' && event.status === 'past');
    
    // فلتر حسب السعر (فقط إذا كان مفعل)
    const matchesPriceFilter = 
      (!isPrice && !isFree) || // إذا لم يتم تفعيل أي فلتر سعر
      (isPrice && event?.price !== 0) || // أحداث مدفوعة
      (isFree && event?.price === 0); // أحداث مجانية

    return matchesSearch && matchesBasicFilter && matchesPriceFilter;
  });

  useEffect(() => {
    fetchEvents({
      token,
      currentPage,
      eventsPerPage,
      activeFilter,
      role: 'user',
      toast,
      setLoading,
    }).then((data) => {
      setEvents(
        data.events.map((event: EventCategory) => ({
          ...event,
          isRegistered: event.registeredUsers.forEach((element) => {
            element === detailsProfile?._id;
          }),
        }))
      );
      setTotalPages(data.totalPages);
      setTotalItems(data.totalItems);
    });
  }, [currentPage, activeFilter]);

  // إعادة تعيين فلاتر السعر عند تغيير الفلتر الأساسي
  useEffect(() => {
    setIsPrice(false);
    setIsFree(false);
  }, [activeFilter]);

  const generateInvoice = async (eventId: string) => {
    if (!token) return;

    setDownloadingInvoice(eventId);
    try {
      const response = await fetch(
        `http://localhost:8080/events/${eventId}/invoice`,
        {
          method: 'GET',
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      );

      if (!response.ok) {
        throw new Error(await response.text());
      }

      // Create blob from response
      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);

      // Create download link
      const a = document.createElement('a');
      a.href = url;
      a.download = `Invoice-${eventId}.pdf`;
      document.body.appendChild(a);
      a.click();

      // Cleanup
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);

      toast({
        title: 'Report downloaded',
        description: 'The invoice has been successfully downloaded.',
        className: 'bg-green-500 text-white',
      });
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error?.message || 'Failed to download invoice',
        className: 'bg-red-600 text-white border-0',
      });
    } finally {
      setDownloadingInvoice(null);
    }
  };

  // Filter events

  const paginate = (pageNumber: number) => setCurrentPage(pageNumber);

  const RegisterUser = async () => {
    if (!selectedEvent) return;
    try {
      const res = await fetch(
        `http://localhost:8080/users/me/events/${selectedEvent._id}/register`,
        {
          method: 'POST',
          headers: {
            Authorization: `Bearer ${token}`,
            'Content-Type': 'application/json',
          },
        }
      );
      const data = await res.json();
      toast({
        title: 'Registration successful',
        description: data?.message || 'An unexpected error occurred.',
        className: 'bg-green-500 text-white border-0',
      });
      if (res.ok) {
        localStorage.setItem(`registered_${selectedEvent._id}`, 'true');
        setEvents((prev) =>
          prev.map((e) =>
            e._id === selectedEvent._id ? { ...e, isRegistered: true } : e
          )
        );

        if (selectedEvent.price !== 0) {
          window.location.href = data.url;
        }
      }
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error?.message || 'An unexpected error occurred.',
        className: 'bg-red-500 text-white border-0',
      });
    }

    setIsRegisterModalOpen(false);
    setSelectedEvent(null);
  };

  const UnregisterUser = async () => {
    if (!selectedEvent) return;

    try {
      const res = await fetch(
        `http://localhost:8080/users/me/events/${selectedEvent._id}/unregister`,
        {
          method: 'DELETE',
          headers: {
            Authorization: `Bearer ${token}`,
            'Content-Type': 'application/json',
          },
        }
      );

      const data = await res.json();
      toast({
        title: 'Unregistration successful',
        description: data?.message || 'An unexpected error occurred.',
        className: 'bg-green-500 text-white border-0',
      });
      if (res.ok) {
        localStorage.removeItem(`registered_${selectedEvent._id}`);
        setEvents((prev) =>
          prev.map((e) =>
            e._id === selectedEvent._id ? { ...e, isRegistered: false } : e
          )
        );
      }
      console.log('events update', events);
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error?.message || 'An unexpected error occurred.',
        className: 'bg-red-500 text-white border-0',
      });
    }

    setIsUnregisterModalOpen(false);
    setSelectedEvent(null);
  };

  if (loading) {
    return (
      <Loading />
    );
  }
  return (
    <section className='px-12 py-12'>
      <h1 className='text-2xl font-bold mb-6 text-center text-purple-800'>
        🎉 My Booked Events
      </h1>
      <div className='flex flex-col md:flex-row gap-4 justify-between items-center mb-6'>
        <div className='relative w-full md:w-1/3 my-6'>
          <div className='absolute inset-y-0 left-0 pl-3 py-3 flex items-center pointer-events-none'>
            <Search className='h-5 w-5 text-purple-400' />
          </div>
          <Input
            placeholder='Search events...'
            className='pl-10 pr-4 py-2 rounded-full border border-purple-300 focus:ring-2 focus:ring-purple-500 focus:border-transparent w-full'
            value={searchQuery}
            onChange={(e) => {
              setSearchQuery(e.target.value);
              setCurrentPage(1);
            }}
          />
        </div>
        <div className='flex flex-wrap gap-2 justify-center'>
          {filters.map(({ label, icon: Icon }, index) => {
            const filterKey = label.toLowerCase() as typeof activeFilter;
            const isActive = activeFilter === filterKey;
            return (
              <motion.button
                key={index}
                whileHover={{ scale: 1.05 }}
                onClick={() => setActiveFilter(filterKey)}
                className={`flex items-center gap-2 px-4 py-2 rounded-full transition-colors
                                ${
                                  isActive
                                    ? 'bg-purple-600 text-white'
                                    : 'bg-gray-200 text-purple-700 hover:bg-purple-100'
                                }`}
              >
                <Icon size={18} /> {label}
              </motion.button>
            );
          })}

            <motion.button
              whileHover={{ scale: 1.05 }}
              onClick={() => {
                setIsFree(!isFree);
                if (!isFree) setIsPrice(false); // إلغاء تفعيل Price عند تفعيل Free
              }}
              className={`flex items-center gap-2 px-4 py-2 rounded-full transition-colors
                              ${
                                isFree
                                  ? 'bg-purple-600 text-white'
                                  : 'bg-gray-200 text-purple-700 hover:bg-purple-100'
                              }`}
            >
              <Gift size={18} />Free
            </motion.button>
            <motion.button
              whileHover={{ scale: 1.05 }}
              onClick={() => {
                setIsPrice(!isPrice);
                if (!isPrice) setIsFree(false); // إلغاء تفعيل Free عند تفعيل Price
              }}
              className={`flex items-center gap-2 px-4 py-2 rounded-full transition-colors
                              ${isPrice
                                  ? 'bg-purple-600 text-white'
                                  : 'bg-gray-200 text-purple-700 hover:bg-purple-100'
                              }`}
            >
              <DollarSign size={18} />Price
            </motion.button>
        </div>
      </div>

      {currentEvents?.length > 0 ? (
          <motion.div
            className='grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-8'
            initial='hidden'
            animate='visible'
            variants={{
              hidden: { opacity: 0 },
              visible: {
                opacity: 1,
                transition: {
                  staggerChildren: 0.1,
                  delayChildren: 0.2,
                },
              },
            }}
          >
            <AnimatePresence>
              {currentEvents ? (
                <>
                  {' '}
                  {currentEvents?.map((event, index) => (
                    <motion.div
                      key={index}
                      variants={{ hidden: { opacity: 0, y: 20 }, visible: { opacity: 1, y: 0 } }}
                      whileHover={{ y: -5, transition: { type: 'spring', stiffness: 300 } }}
                      className='relative group'
                    >
                      <EventCard
                        event={event}
                        href={`events/${event._id}`}
                        className='transition-all duration-300 group-hover:shadow-xl group-hover:shadow-purple-500/20 group-hover:border-cyan-400/30'
                        footer={
                          <div className='flex items-center gap-3'>
                              <Button
                                variant='outline'
                                className={`flex items-center gap-2 text-white ${localStorage.getItem(`registered_${event._id}`) ? 'bg-red-600' : 'bg-purple-500'}`}
                                onClick={() => {
                                  setSelectedEvent(event);
                                  if (localStorage.getItem(`registered_${event._id}`)) {
                                    setIsUnregisterModalOpen(true);
                                  } else {
                                    setIsRegisterModalOpen(true);
                                  }
                                }}
                              >
                                { localStorage.getItem(`registered_${event._id}`)? 'Unregister' : 'Register'}
                              </Button>
                            {typeof event.price === 'number' && (
                                <span className='bg-purple-50 text-purple-800 font-medium px-3 py-1 rounded-full text-sm shadow-sm'>
                                {event.price === 0 ? 'FREE' : `${event.price} UE`}
                                </span>
                            )}
                          </div>
                        }
                      />
                      <motion.div
                        initial={{ scale: 0 }}
                        animate={{ scale: 1 }}
                        className='absolute top-2 right-2 p-2 bg-purple-600/80 rounded-full backdrop-blur-sm'
                      >
                      </motion.div>
                    </motion.div>
                  ))}
                </>
              ) : (
                <NotFound message='No events found' />
              )}
            </AnimatePresence>
          </motion.div>
        ) : (
          <NotFound message='No events found' />
        )}
      {/* Pagination Controls */}
      {currentEvents.length > 0 && (
        <Pagination
          currentPage={currentPage}
          totalPages={totalPages}
          totalItems={totalItems}
          paginate={paginate}
        />
      )}
      {/* Unregister Confirmation Modal */}
      <UnregisterConfirmationDialog
        open={isUnregisterModalOpen}
        onOpenChange={setIsUnregisterModalOpen}
        onConfirm={() => UnregisterUser()}
        event={selectedEvent}
      />
      <RegisterConfirmationDialog
        open={isRegisterModalOpen}
        onOpenChange={setIsRegisterModalOpen}
        onConfirm={() => RegisterUser()}
        event={selectedEvent}
      />
    </section>
  );
};

export default UserDashboard;